import React from "react";

const Contact = () => {
  return (
    <section style={{ padding: "40px" }}>
      <h2>Contact Us</h2>
      <input placeholder="Your Name" />
      <br />
      <input placeholder="Your Email" />
      <br />
      <button>Submit</button>
    </section>
  );
};

export default Contact;
